import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";
import { PriceSource } from "@prisma/client";
import { prisma } from "../../../lib/prisma";
import VariantCompareClient from "./variant-compare-client";
import Header from "../../../layouts/header";
import Footer from "../../../layouts/footer";

function formatPriceFullIdr(value: bigint | null | undefined): string {
  if (!value) return "Price on request";
  return `Rp ${Number(value).toLocaleString("id-ID")} IDR`;
}

function normalizeSpecKey(value: string): string {
  return value.replace(/\s+/g, " ").trim();
}

export default async function CarDetailPage({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;

  const activePriceList = await prisma.priceList.findFirst({
    where: {
      source: PriceSource.OTR_IMAGE,
      isActive: true,
    },
    orderBy: { createdAt: "desc" },
  });

  const model = await prisma.carModel.findUnique({
    where: { slug },
    include: {
      colors: {
        orderBy: { sortOrder: "asc" },
      },
      variants: {
        orderBy: { sortOrder: "asc" },
        include: {
          specs: {
            orderBy: [{ specGroup: "asc" }, { sortOrder: "asc" }],
          },
          prices: activePriceList
            ? {
                where: { priceListId: activePriceList.id },
                orderBy: { otrPrice: "asc" },
              }
            : false,
        },
      },
      prices: activePriceList
        ? {
            where: { priceListId: activePriceList.id },
            orderBy: { otrPrice: "asc" },
          }
        : false,
    },
  });

  if (!model) {
    notFound();
  }

  const compareVariants = model.variants.slice(0, 3);

  const performanceKeys = Array.from(
    new Set(
      compareVariants.flatMap((variant) =>
        variant.specs
          .filter((spec) => spec.specGroup.toUpperCase() === "PERFORMANCE")
          .map((spec) => normalizeSpecKey(spec.specKey)),
      ),
    ),
  );

  const featureKeys = Array.from(
    new Set(
      compareVariants.flatMap((variant) =>
        variant.specs
          .filter((spec) => spec.specGroup.toUpperCase() === "KEY_FEATURES")
          .map((spec) => normalizeSpecKey(spec.specKey)),
      ),
    ),
  );

  const valueByVariantAndKey = new Map<string, string>();
  for (const variant of compareVariants) {
    for (const spec of variant.specs) {
      valueByVariantAndKey.set(`${variant.id}::${normalizeSpecKey(spec.specKey)}`, spec.specValue);
    }
  }

  return (
    <main className="min-h-screen bg-foreground">
      <Header />
      <div className="container mx-auto px-4 py-12">
        <Link href="/" className="inline-flex items-center text-sm text-white/80 hover:text-white hover:underline mb-6">
          Back to home
        </Link>

        <section id="fronx" className="mb-10">
          <h1 className="text-4xl font-suzuki-pro-headline text-white">{model.name}</h1>
          <p className="font-sans text-lg tracking-wide text-primary-suzuki mt-2">
            SEE WHICH {model.name.toUpperCase()} IS PERFECTLY RIGHT FOR YOU
          </p>
        </section>

        <section className="mb-8 border border-white/10 bg-black/25 backdrop-blur-sm px-4 py-3">
          <nav className="flex flex-wrap items-center gap-2 text-xs sm:text-sm font-sans uppercase tracking-wide">
            <a href="#fronx" className="px-3 py-1 border border-white/20 text-white hover:border-primary-suzuki hover:text-primary-suzuki">
              {model.name}
            </a>
            <a href="#eksterior" className="px-3 py-1 border border-white/20 text-white hover:border-primary-suzuki hover:text-primary-suzuki">
              Eksterior
            </a>
            <a href="#interior" className="px-3 py-1 border border-white/20 text-white hover:border-primary-suzuki hover:text-primary-suzuki">
              Interior
            </a>
            <a href="#fitur-safety" className="px-3 py-1 border border-white/20 text-white hover:border-primary-suzuki hover:text-primary-suzuki">
              Fitur Safety
            </a>
            <a href="#aksesori" className="px-3 py-1 border border-white/20 text-white hover:border-primary-suzuki hover:text-primary-suzuki">
              Aksesori
            </a>
            <a href="#variant" className="px-3 py-1 border border-primary-suzuki text-primary-suzuki">
              Variant
            </a>
          </nav>
        </section>

        <section id="variant">
          <VariantCompareClient
            modelName={model.name}
            heroImage={model.heroImage}
            variants={compareVariants.map((variant) => ({
              id: variant.id,
              name: variant.name,
              priceText: formatPriceFullIdr(variant.prices[0]?.otrPrice),
            }))}
            colors={model.colors.map((color) => ({
              id: color.id,
              name: color.name,
              imageUrl: color.imageUrl,
              hexCodePrimary: color.hexCodePrimary,
              hexCodeSecondary: color.hexCodeSecondary,
            }))}
          />
        </section>

        <section id="eksterior" className="mt-10 border border-white/10 bg-black/25 backdrop-blur-sm">
          <h2 className="px-4 py-3 font-suzuki-pro-headline text-2xl text-white border-b border-white/10">PERFORMANCE</h2>
          <div className="overflow-x-auto">
            <table className="w-full min-w-[840px] text-sm">
              <tbody>
                {performanceKeys.map((key) => (
                  <tr key={key} className="border-b border-white/10">
                    <td className="px-4 py-3 w-72 font-sans text-white/70">{key}</td>
                    {compareVariants.map((variant) => (
                      <td key={`${variant.id}-${key}`} className="px-4 py-3 font-sans text-white">
                        {valueByVariantAndKey.get(`${variant.id}::${key}`) ?? "-"}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section id="fitur-safety" className="mt-8 border border-white/10 bg-black/25 backdrop-blur-sm">
          <h2 className="px-4 py-3 font-suzuki-pro-headline text-2xl text-white border-b border-white/10">KEY FEATURES</h2>
          <div className="overflow-x-auto">
            <table className="w-full min-w-[840px] text-sm">
              <tbody>
                {featureKeys.map((key) => (
                  <tr key={key} className="border-b border-white/10">
                    <td className="px-4 py-3 w-72 font-sans text-white/70">{key}</td>
                    {compareVariants.map((variant) => (
                      <td key={`${variant.id}-${key}`} className="px-4 py-3 font-sans text-white">
                        {valueByVariantAndKey.get(`${variant.id}::${key}`) ?? "-"}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section id="interior" className="mt-8 border border-white/10 bg-black/25 backdrop-blur-sm p-4">
          <h2 className="font-sans font-semibold text-white mb-3">All Variants</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
            {model.variants.map((variant) => (
              <div key={variant.id} className="border border-white/10 p-3 bg-black/20">
                <p className="font-sans text-sm text-white/80">{variant.name}</p>
                <p className="font-sans font-medium text-white mt-1">
                  {formatPriceFullIdr(variant.prices[0]?.otrPrice)}
                </p>
              </div>
            ))}
          </div>
        </section>

        <section id="aksesori" className="mt-8 border border-white/10 bg-black/25 backdrop-blur-sm p-4">
          <h2 className="font-sans font-semibold text-white mb-3">Available Colors</h2>
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-2">
            {model.colors.map((color) => (
              <div key={color.id} className="border border-white/10 p-2 bg-black/20">
                <div className="relative w-full aspect-video bg-black/30 mb-2">
                  <Image
                    src={color.imageUrl ?? "https://placehold.co/300x180/111827/9ca3af?text=Color"}
                    alt={color.name}
                    fill
                    className="object-cover"
                    unoptimized
                  />
                </div>
                <p className="text-xs font-sans text-white/80 line-clamp-2">{color.name}</p>
              </div>
            ))}
          </div>
        </section>
      </div>
      <Footer />
    </main>
  );
}
